#include <stdio.h>
#include <stdlib.h>

typedef struct {int x1,y1,x2,y2;} Seg;

int main(){
    int n,m; if(scanf("%d %d",&n,&m)!=2) return 0;
    Seg *seg = (Seg*)malloc(sizeof(Seg)*n);
    for(int i=0;i<n;i++) scanf("%d %d %d %d",&seg[i].x1,&seg[i].y1,&seg[i].x2,&seg[i].y2);
    int prev=0;
    for(int i=0;i<m;i++){
        int x,y,r; scanf("%d %d %d",&x,&y,&r);
        if(i>0){ x ^= prev; y ^= prev; }
        int xmin = x - r, xmax = x + r, ymin = y - r, ymax = y + r;
        int cnt = 0;
        for(int j=0;j<n;j++){
            int a=seg[j].x1, b=seg[j].y1, c=seg[j].x2, d=seg[j].y2;
            if( (a < xmin && c < xmin) || (a > xmax && c > xmax) ||
                (b < ymin && d < ymin) || (b > ymax && d > ymax) ) continue;
            cnt++;
        }
        prev = cnt;
    }
    printf("%d\n",prev);
    free(seg);
    return 0;
}

