import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
    static class Seg {int x1,y1,x2,y2;}
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int n = fs.nextInt();
        int m = fs.nextInt();
        Seg[] seg = new Seg[n];
        for (int i = 0; i < n; i++) {
            Seg s = new Seg();
            s.x1 = fs.nextInt(); s.y1 = fs.nextInt(); s.x2 = fs.nextInt(); s.y2 = fs.nextInt();
            seg[i] = s;
        }
        int prev = 0;
        for (int i = 0; i < m; i++) {
            int x = fs.nextInt();
            int y = fs.nextInt();
            int r = fs.nextInt();
            if (i > 0) { x ^= prev; y ^= prev; }
            int xmin = x - r, xmax = x + r, ymin = y - r, ymax = y + r;
            int cnt = 0;
            for (Seg s : seg) {
                if ((s.x1 < xmin && s.x2 < xmin) || (s.x1 > xmax && s.x2 > xmax) ||
                    (s.y1 < ymin && s.y2 < ymin) || (s.y1 > ymax && s.y2 > ymax)) continue;
                cnt++;
            }
            prev = cnt;
        }
        System.out.println(prev);
    }
}

